import React, { useState } from 'react';
import img1 from '../img/image1.png';
import img2 from '../img/image2.png';
import img3 from '../img/image3.png';
import img4 from '../img/image4.png';
import img5 from '../img/image5.png';

interface Photo {
  id: number;
  emoji: string;
  caption: string;
  color: string;
  label: string;
  image: string;
}

const photos: Photo[] = [
  { id: 1, emoji: '💍', caption: 'Ring Ceremony', color: 'from-rose-900 to-red-950', label: 'The Promise', image: '/img/image1.png' },
  { id: 2, emoji: '🌺', caption: 'Mehendi Night', color: 'from-emerald-900 to-green-950', label: 'Henna Night', image: '/img/image2.png' },
  { id: 3, emoji: '🎊', caption: 'Haldi Ceremony', color: 'from-yellow-800 to-amber-950', label: 'Turmeric Glow', image: '/img/image3.png' },
  { id: 4, emoji: '🪔', caption: 'Temple Blessing', color: 'from-orange-900 to-red-950', label: 'Sacred Moments', image: '/img/image4.png' },
  { id: 5, emoji: '👗', caption: 'Bridal Look', color: 'from-pink-900 to-rose-950', label: 'The Bride', image: '/img/image5.png' },
];


const PhotoGallery: React.FC = () => {
  const [lightbox, setLightbox] = useState<Photo | null>(null);

  return (
    <section style={{ minHeight: '100vh', padding: '80px 20px', position: 'relative', overflow: 'hidden' }}>
      <div style={{ maxWidth: 1100, margin: '0 auto' }}>
        <h2 style={{ textAlign: 'center', color: '#FFD700', marginBottom: 40 }}>Our Gallery</h2>

        {/* Gallery grid */}
        <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(280px, 1fr))', gap: 20 }}>
          {photos.map((photo) => (
            <div
              key={photo.id}
              onClick={() => setLightbox(photo)}
              style={{
                position: 'relative',
                borderRadius: 8,
                overflow: 'hidden',
                cursor: 'pointer',
                boxShadow: '0 4px 20px rgba(0,0,0,0.4)',
                transition: 'transform 0.3s ease, box-shadow 0.3s ease',
              }}
              onMouseEnter={(e) => (e.currentTarget.style.transform = 'scale(1.03)')}
              onMouseLeave={(e) => (e.currentTarget.style.transform = 'scale(1)')}
            >
              {/* Image */}
              <img
                src={photo.image}
                alt={photo.label}
                style={{ width: '100%', height: '100%', objectFit: 'cover', display: 'block' }}
              />

              {/* Overlay for text */}
              <div
                style={{
                  position: 'absolute',
                  bottom: 0,
                  left: 0,
                  right: 0,
                  padding: '12px 16px',
                  background: 'linear-gradient(180deg, transparent 0%, rgba(0,0,0,0.7) 100%)',
                  color: '#FFD700',
                }}
              >
                <div style={{ fontSize: 18 }}>{photo.label}</div>
                <div style={{ fontSize: 12, opacity: 0.8 }}>{photo.caption}</div>
              </div>
            </div>
          ))}
        </div>
      </div>

      {/* Lightbox */}
      {lightbox && (
        <div
          onClick={() => setLightbox(null)}
          style={{
            position: 'fixed',
            inset: 0,
            background: 'rgba(0,0,0,0.9)',
            display: 'flex',
            justifyContent: 'center',
            alignItems: 'center',
            zIndex: 9999,
          }}
        >
          <img src={lightbox.image} alt={lightbox.label} style={{ maxWidth: '90%', maxHeight: '80%', borderRadius: 12 }} />
        </div>
      )}
    </section>
  );
};

export default PhotoGallery;
